  source = "./modules/api"
  provider = aws
  region = "us-east-1"
}

module "api_gcp" {
  source = "./modules/api"
  provider = google
  region = "us-central1"
}

module "api_azure" {
  source = "./modules/api"
  provider = azurerm
  region = "eastus"
}

